        weakAcids: {
            principle:   "Weak acids partially dissociate. Ka = [H⁺][A⁻]/[HA]. Using the approximation that [H⁺] = [A⁻] and that dissociation is small (so [HA]equilibrium ≈ [HA]initial), Ka ≈ [H⁺]²/c, giving [H⁺] = √(Ka × c).",
            kaExpression: "HA ⇌ H⁺ + A⁻     Ka = [H⁺][A⁻]/[HA]",
            approximation: "Valid when Ka << c (degree of dissociation < 5%). Always verify after calculating.",
            workedExample: {
                title: "pH of a Weak Acid Using the Ka Approximation",
                problem: "Calculate the pH of 0.100 mol dm⁻³ ethanoic acid (CH₃COOH). Ka = 1.74 × 10⁻⁵ mol dm⁻³ at 25°C.",
                steps: [
                    {
                        step: 1,
                        action: "Write the dissociation equilibrium and Ka expression",
                        working: "CH₃COOH ⇌ CH₃COO⁻ + H⁺\nKa = [CH₃COO⁻][H⁺] / [CH₃COOH]",
                        result: "Ka expression confirmed"
                    },
                    {
                        step: 2,
                        action: "Apply the approximation",
                        working: "Let [H⁺] = x. Since Ka << c (1.74 × 10⁻⁵ << 0.100), dissociation is small: [CH₃COOH] ≈ 0.100 mol dm⁻³. [CH₃COO⁻] = [H⁺] = x. Therefore: Ka = x²/0.100",
                        result: "x² = Ka × c = 1.74 × 10⁻⁵ × 0.100 = 1.74 × 10⁻⁶"
                    },
                    {
                        step: 3,
                        action: "Solve for [H⁺]",
                        working: "x = √(1.74 × 10⁻⁶) = 1.319 × 10⁻³ mol dm⁻³",
                        result: "[H⁺] = 1.32 × 10⁻³ mol dm⁻³"
                    },
                    {
                        step: 4,
                        action: "Verify the approximation is valid",
                        working: "Degree of dissociation = (1.32 × 10⁻³ / 0.100) × 100% = 1.32%. This is less than 5%, so the approximation is valid.",
                        result: "Approximation valid ✓"
                    },
                    {
                        step: 5,
                        action: "Calculate pH",
                        working: "pH = −log₁₀(1.319 × 10⁻³)",
                        result: "pH = 2.88 (3 s.f.)"
                    }
                ],
                answer: "pH = 2.88",
                commonError: "Forgetting to verify the approximation. If degree of dissociation > 5%, the quadratic must be solved: Ka[HA] = x² + Kax, rearranged to x² + Kax − Ka[HA] = 0."
            }
        },

