    bufferSolutions: {
        composition: {
            acidBuffer:  "Weak acid + its conjugate base (e.g. CH₃COOH + CH₃COO⁻Na⁺) — resists pH change in the acidic range",
            alkalineBuffer: "Weak base + its conjugate acid (e.g. NH₃ + NH₄Cl) — resists pH change in the alkaline range"
        },
        mechanism: {
            addAcid: {
                description: "When H⁺ is added, the conjugate base (A⁻) neutralises it: A⁻ + H⁺ → HA. The equilibrium shifts to the left, consuming H⁺ and forming more weak acid. [H⁺] barely changes because A⁻ is present in large reservoir.",
                equation:    "CH₃COO⁻ + H⁺ → CH₃COOH"
            },
            addAlkali: {
                description: "When OH⁻ is added, the weak acid neutralises it: HA + OH⁻ → A⁻ + H₂O. The equilibrium shifts to the right, consuming OH⁻. [OH⁻] barely changes because HA is present in large reservoir.",
                equation:    "CH₃COOH + OH⁻ → CH₃COO⁻ + H₂O"
            },
            whyResists: "The buffer resists pH change because both a proton donor (HA) and proton acceptor (A⁻) are simultaneously present in comparable concentrations. Neither added H⁺ nor added OH⁻ escapes neutralisation."
        },
        hendersonHasselbalch: {
            equation:     "pH = pKa + log₁₀([A⁻]/[HA])",
            derivation:   "From Ka = [H⁺][A⁻]/[HA], rearrange: [H⁺] = Ka × [HA]/[A⁻]. Take −log₁₀ of both sides: pH = pKa − log([HA]/[A⁻]) = pKa + log([A⁻]/[HA]).",
            halfEquivalencePoint: "When [A⁻] = [HA], log(1) = 0, so pH = pKa. At the half-equivalence point of a weak acid titration, pH = pKa of the weak acid.",
            workedExample: {
                title: "Calculating Buffer pH Using the Henderson–Hasselbalch Equation",
                problem: "A buffer is prepared by dissolving 0.400 mol of sodium ethanoate (CH₃COONa) and 0.600 mol of ethanoic acid (CH₃COOH) in water to make 1.00 dm³ of solution. Calculate the pH of this buffer. Ka(CH₃COOH) = 1.74 × 10⁻⁵ mol dm⁻³.",
                steps: [
                    {
                        step: 1,
                        action: "Identify [A⁻] and [HA]",
                        working: "[CH₃COO⁻] = 0.400 mol dm⁻³ (from sodium ethanoate, fully dissociates)\n[CH₃COOH] = 0.600 mol dm⁻³",
                        result: "[A⁻] = 0.400, [HA] = 0.600 mol dm⁻³"
                    },
                    {
                        step: 2,
                        action: "Calculate pKa",
                        working: "pKa = −log₁₀(1.74 × 10⁻⁵) = 4.76",
                        result: "pKa = 4.76"
                    },
                    {
                        step: 3,
                        action: "Apply Henderson–Hasselbalch",
                        working: "pH = pKa + log([A⁻]/[HA]) = 4.76 + log(0.400/0.600) = 4.76 + log(0.667) = 4.76 + (−0.176)",
                        result: "pH = 4.76 − 0.176 = 4.58"
                    }
                ],
                answer: "pH = 4.58",
                commonError: "Inverting the ratio — writing log([HA]/[A⁻]) instead of log([A⁻]/[HA]). The Henderson–Hasselbalch equation always has [A⁻] (conjugate base) in the numerator. When [A⁻] < [HA], the log term is negative and pH < pKa — which makes chemical sense (more acid present shifts pH below pKa)."
            }
        }
    },

